var el = document.querySelector(".reveal");
var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  var fade = Math.max(0, Math.min(1, (p - 0.05) / 0.7));
  var c = Math.round(82 + (255 - 82) * fade);
  el.style.color = "rgb(" + c + "," + c + "," + c + ")";
}, { passive: true });

.scroll-track { min-height: 240vh; }
.sticky-stage { position: sticky; top: 0; height: 100vh; display: flex; align-items: center; justify-content: center; }
.reveal { color: #525252; }
.reveal .w { display: inline-block; transition: color 200ms ease; }
.reveal .w.on { color: #fff; }

var el = document.querySelector(".reveal");
var words = el.textContent.split(" ");
el.innerHTML = words.map(function(w){ return "<span class=\"w\">" + w + "</span>"; }).join(" ");
var spans = el.querySelectorAll(".w");
var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  var idx = Math.floor(p * (spans.length + 1));
  spans.forEach(function(s, i){ s.classList.toggle("on", i < idx); });
}, { passive: true });

.reveal {
  background: linear-gradient(90deg, #ffffff 50%, #525252 50%);
  background-size: 200% 100%;
  background-position: 100% 0;
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
}

var el = document.querySelector(".reveal");
var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  el.style.backgroundPosition = (100 - p * 100) + "% 0";
}, { passive: true });

var el = document.querySelector(".reveal");
el.innerHTML = el.textContent.split("").map(function(c){ return "<span class=\"c\">" + (c === " " ? "&nbsp;" : c) + "</span>"; }).join("");
var chars = el.querySelectorAll(".c");
var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  chars.forEach(function(c, i){
    var startP = i / (chars.length + 1);
