.reveal {
  font-family: "Pretendard Variable","Pretendard",system-ui;
  font-variation-settings: "wght" 100;
  font-weight: 100;
}

var el = document.querySelector(".reveal");
var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  var w = Math.round(100 + 800 * p);
  el.style.fontVariationSettings = "\"wght\" " + w;
  el.style.fontWeight = w;
}, { passive: true });

.reveal { display: inline-flex; flex-direction: column; gap: 12px; align-items: flex-start; }
.reveal .t { opacity: 0; transform: translateY(20px); }
.reveal .u { display: block; height: 4px; width: 100%; background: currentColor; transform: scaleX(0); transform-origin: left; }

var textEl = document.querySelector(".reveal .t");
var lineEl = document.querySelector(".reveal .u");
var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  var textP = Math.max(0, Math.min(1, p / 0.5));
  textEl.style.opacity = textP;
  textEl.style.transform = "translateY(" + (20 * (1 - textP)) + "px)";
  var lineP = Math.max(0, Math.min(1, (p - 0.3) / 0.65));
  lineEl.style.transform = "scaleX(" + lineP + ")";
}, { passive: true });
